
.exchange-card {
  background: var(--card-bg);
  border: 2px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: var(--spacing-md);
}

.exchange-card--gold {
  --exchange-accent: #d4af37;
  --exchange-accent-strong: #b8941f;
  --exchange-surface-start: rgba(212, 175, 55, 0.1);
  --exchange-surface-end: rgba(212, 175, 55, 0.05);
  --exchange-border: rgba(212, 175, 55, 0.3);
  --exchange-secondary-start: #caa336;
  --exchange-secondary-end: #a57f1a;
}

.exchange-card--violet {
  --exchange-accent: #9c27b0;
  --exchange-accent-strong: #7b1fa2;
  --exchange-surface-start: rgba(156, 39, 176, 0.1);
  --exchange-surface-end: rgba(156, 39, 176, 0.05);
  --exchange-border: rgba(156, 39, 176, 0.3);
  --exchange-secondary-start: #d4af37;
  --exchange-secondary-end: #b8941f;
}

.exchange-header {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  margin-bottom: var(--spacing-md);
  padding-bottom: var(--spacing-sm);
  border-bottom: 1px solid var(--border-color);

  .exchange-icon {
    font-size: 1.2rem;
    color: var(--exchange-accent);
  }

  .exchange-title {
    font-size: 1rem;
    font-weight: 600;
    color: var(--title-color);
  }

  .exchange-rate {
    font-size: 0.85rem;
    color: var(--text-light);
  }

  .mobile-current,
  .exchange-toggle {
    display: none;
  }
}

.exchange-body {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);

  .current-display {
    display: flex;
    align-items: baseline;
    gap: var(--spacing-xs);
    padding: var(--spacing-sm) var(--spacing-md);
    background: linear-gradient(
      135deg,
      var(--exchange-surface-start) 0%,
      var(--exchange-surface-end) 100%
    );
    border: 1px solid var(--exchange-border);
    border-radius: var(--radius-md);
    white-space: nowrap;

    .label {
      font-size: 0.9rem;
      color: var(--text-light);
    }

    .value {
      font-size: 1.2rem;
      font-weight: 700;
      color: var(--exchange-accent);
      font-family: var(--font-mono);
      min-width: 40px;
      text-align: right;
    }

    .unit {
      font-size: 0.85rem;
      color: var(--text-light);
    }
  }

  .exchange-controls {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    flex: 1;

    .exchange-input {
      width: 150px;
    }

    .exchange-button,
    .exchange-all-button {
      padding: var(--spacing-sm) var(--spacing-lg);
      background: linear-gradient(
        135deg,
        var(--exchange-accent) 0%,
        var(--exchange-accent-strong) 100%
      );
      color: var(--primary-bg);
      border: none;
      border-radius: var(--radius-md);
      font-size: 0.9rem;
      font-weight: 600;
      cursor: pointer;
      transition: var(--transition-normal);
      white-space: nowrap;

      &:hover:not(:disabled) {
        transform: translateY(-1px);
        box-shadow: var(--shadow-sm);
      }

      &:active:not(:disabled) {
        transform: translateY(0);
      }

      &:disabled {
        opacity: 0.5;
        cursor: not-allowed;
        background: var(--border-color-light);
        color: var(--text-light);

        &:hover {
          transform: none;
          box-shadow: none;
        }
      }
    }

    .exchange-all-button {
      background: linear-gradient(
        135deg,
        var(--exchange-secondary-start) 0%,
        var(--exchange-secondary-end) 100%
      );
    }

    .exchange-reset-icon {
      width: 32px;
      height: 32px;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      border-radius: var(--radius-sm);
      border: 1px solid var(--border-color);
      background: transparent;
      color: var(--text-light);
      cursor: pointer;
      transition: var(--transition-fast);

      &:hover:not(:disabled) {
        color: var(--exchange-accent-strong);
        border-color: var(--exchange-accent-strong);
      }

      &:disabled {
        opacity: 0.4;
        cursor: not-allowed;
      }
    }
  }
}

@media (max-width: 768px) {
  .exchange-card {
    padding: var(--spacing-sm);
    border-width: 1px;
    border-radius: var(--radius-md);
  }

  .exchange-header {
    margin-bottom: 0;
    padding-bottom: 0;
    border-bottom: none;

    .exchange-icon {
      font-size: 1rem;
    }

    .exchange-title {
      font-size: 0.9rem;
    }

    .exchange-rate {
      display: none;
    }

    .mobile-current {
      display: inline-flex;
      margin-left: auto;
      color: var(--exchange-accent-strong);
      font-family: var(--font-mono);
      font-weight: 700;
      font-size: 0.9rem;
      white-space: nowrap;
    }

    .exchange-toggle {
      min-height: 34px;
      display: inline-flex;
      align-items: center;
      gap: 4px;
      padding: 5px 8px;
      border: 1px solid var(--border-color);
      border-radius: var(--radius-md);
      background: var(--input-bg);
      color: var(--title-color);
      font-size: 0.8rem;
      font-weight: 600;
      cursor: pointer;

      i {
        font-size: 0.7rem;
        transition: transform var(--transition-fast);

        &.rotated {
          transform: rotate(180deg);
        }
      }
    }
  }

  .exchange-body {
    margin-top: var(--spacing-sm);
    padding-top: var(--spacing-sm);
    border-top: 1px solid var(--border-color);
    flex-direction: column;
    align-items: stretch;

    .current-display {
      justify-content: space-between;
    }

    .exchange-controls {
      display: grid;
      grid-template-columns: 1fr auto auto;
      gap: var(--spacing-xs);

      .exchange-input {
        width: auto;
        min-width: 0;
      }

      .exchange-button,
      .exchange-all-button,
      .exchange-reset-icon {
        min-height: 38px;
        flex-shrink: 0;
      }

      .exchange-button {
        grid-column: 1 / -1;
      }

      .exchange-all-button {
        padding: var(--spacing-sm);
      }

      .exchange-reset-icon {
        width: 38px;
        height: 38px;
      }
    }
  }
}
