
.library-manager {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

.worldbook-section,
.editor-section,
.list-section {
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  background: rgba(255, 249, 240, 0.58);
  padding: var(--spacing-md);
}

.section-heading {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-md);

  h3 {
    display: inline-flex;
    align-items: center;
    gap: var(--spacing-sm);
    margin: 0;
    color: var(--title-color);
    font-size: 1rem;
    font-family: var(--font-body);
    letter-spacing: 0;

    i {
      color: var(--accent-color);
    }
  }
}

.worldbook-row,
.inline-row,
.effect-editor {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto auto;
  gap: var(--spacing-sm);
  align-items: center;
}

.inline-row {
  grid-template-columns: minmax(0, 1fr) auto;
}

.effect-editor {
  grid-template-columns: minmax(0, 0.7fr) minmax(0, 1fr) auto;
}

.helper-text {
  margin: var(--spacing-sm) 0 0;
  color: var(--text-light);
  font-size: 0.82rem;
  line-height: 1.5;
}

.form-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: var(--spacing-md);

  .short {
    max-width: 180px;
  }
}

.field {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
  margin-bottom: var(--spacing-md);

  > span {
    color: var(--title-color);
    font-size: 0.88rem;
    font-weight: 700;
  }
}

.text-input,
.text-area {
  width: 100%;
  min-width: 0;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  background: var(--input-bg);
  color: var(--text-color);
  font: inherit;
  font-size: 0.9rem;
  padding: var(--spacing-sm);

  &:focus {
    outline: none;
    border-color: var(--accent-color);
    box-shadow: 0 0 0 2px rgba(212, 175, 55, 0.18);
  }
}

.text-area {
  resize: vertical;
}

.rarity-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(70px, 1fr));
  gap: var(--spacing-xs);
}

.rarity-button,
.manager-button,
.icon-button,
.tag-chip {
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: var(--transition-fast);
}

.rarity-button {
  min-height: 34px;
  border: 1px solid var(--border-color);
  background: var(--input-bg);
  color: var(--text-color);
  font-weight: 700;

  &.active {
    border-color: var(--rarity-color);
    background: color-mix(in srgb, var(--rarity-color) 16%, var(--input-bg));
    color: var(--title-color);
    box-shadow: inset 0 -2px 0 var(--rarity-color);
  }
}

.manager-button {
  min-height: 34px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  border: 1px solid var(--border-color);
  background: var(--input-bg);
  color: var(--title-color);
  font-size: 0.84rem;
  font-weight: 700;
  padding: 6px var(--spacing-sm);
  white-space: nowrap;

  &:hover:not(:disabled) {
    border-color: var(--accent-color);
    box-shadow: var(--shadow-sm);
  }

  &.primary {
    background: var(--accent-color);
    border-color: var(--accent-color);
    color: var(--primary-bg);
  }

  &.danger {
    color: var(--error-color);
    border-color: rgba(211, 47, 47, 0.35);
    background: rgba(211, 47, 47, 0.06);
  }

  &.subtle {
    background: transparent;
  }

  &:disabled {
    opacity: 0.55;
    cursor: not-allowed;
  }
}

.tag-list {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-xs);

  &.compact {
    margin-top: var(--spacing-xs);
  }
}

.tag-chip {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  min-height: 28px;
  border: 1px solid rgba(212, 175, 55, 0.38);
  background: rgba(212, 175, 55, 0.12);
  color: var(--title-color);
  font-size: 0.8rem;
  font-weight: 700;
  padding: 4px 8px;

  &.passive {
    cursor: default;
  }
}

.effect-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xs);
  margin-bottom: var(--spacing-xs);
}

.effect-row {
  display: grid;
  grid-template-columns: minmax(90px, 0.4fr) minmax(0, 1fr) auto;
  gap: var(--spacing-sm);
  align-items: center;
  padding: var(--spacing-xs) var(--spacing-sm);
  border: 1px dashed var(--border-color);
  background: rgba(255, 249, 240, 0.62);

  strong,
  span {
    min-width: 0;
    overflow-wrap: anywhere;
  }
}

.icon-button {
  width: 28px;
  height: 28px;
  border: 1px solid var(--border-color);
  background: var(--input-bg);
  color: var(--text-light);

  &.danger {
    color: var(--error-color);
  }
}

.form-actions,
.list-tools,
.item-actions {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  justify-content: flex-end;
}

.empty-state {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-xl) var(--spacing-md);
  border: 1px dashed var(--border-color);
  color: var(--text-light);
  text-align: center;
}

.library-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.library-item {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: var(--spacing-md);
  padding: var(--spacing-md);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  background: var(--input-bg);
}

.item-main {
  min-width: 0;
}

.item-title-row,
.item-meta {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-xs);
}

.item-title {
  color: var(--title-color);
  font-size: 0.95rem;
}

.rarity-pill {
  border: 1px solid var(--rarity-color);
  background: color-mix(in srgb, var(--rarity-color) 12%, var(--input-bg));
  color: var(--title-color);
  border-radius: var(--radius-sm);
  padding: 1px 6px;
  font-size: 0.76rem;
  font-weight: 700;
}

.item-meta {
  margin-top: 3px;
  color: var(--text-light);
  font-size: 0.8rem;

  span:not(:last-child)::after {
    content: '·';
    margin-left: var(--spacing-xs);
  }
}

.effect-preview {
  display: flex;
  flex-direction: column;
  gap: 2px;
  margin-top: var(--spacing-xs);
  color: var(--text-color);
  font-size: 0.82rem;
}

.item-description {
  margin: var(--spacing-xs) 0 0;
  color: var(--text-light);
  font-size: 0.84rem;
  line-height: 1.5;
  overflow-wrap: anywhere;
}

@media (max-width: 640px) {
  .worldbook-row,
  .inline-row,
  .effect-editor,
  .form-grid,
  .library-item {
    grid-template-columns: 1fr;
  }

  .section-heading {
    align-items: stretch;
    flex-direction: column;
  }

  .list-tools,
  .form-actions,
  .item-actions {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .list-tools {
    grid-template-columns: 1fr;
  }

  .form-grid .short {
    max-width: none;
  }

  .effect-row {
    grid-template-columns: 1fr auto;

    span {
      grid-column: 1 / -1;
    }
  }
}
