
.selected-panel {
  background: var(--card-bg);
  border: 2px solid var(--border-color);
  border-radius: var(--radius-lg);
  display: flex;
  flex-direction: column;
  height: 100%;

  .panel-header {
    padding: var(--spacing-md);
    border-bottom: 2px solid var(--border-color);
    display: flex;
    flex-direction: column;
    gap: var(--spacing-xs);

    .header-top {
      display: flex;
      justify-content: space-between;
      align-items: center;
      gap: var(--spacing-sm);
    }

    .title {
      font-size: 1.1rem;
      margin: 0;
      color: var(--title-color);
      font-weight: 700;
    }

    .header-actions {
      display: inline-flex;
      align-items: center;
      justify-content: flex-end;
      gap: var(--spacing-xs);
      flex: none;
    }

    .batch-toggle {
      min-height: 32px;
      display: inline-flex;
      align-items: center;
      gap: 6px;
      padding: 6px var(--spacing-sm);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-sm);
      background: var(--input-bg);
      color: var(--title-color);
      font-size: 0.82rem;
      font-weight: 700;
      cursor: pointer;
      transition: all var(--transition-fast);

      i {
        color: var(--accent-color);
      }

      &:hover,
      &.active {
        background: var(--accent-color);
        border-color: var(--accent-color);
        color: var(--primary-bg);

        i {
          color: currentColor;
        }
      }
    }

    .count-badge {
      display: flex;
      align-items: center;
      justify-content: center;
      min-width: 32px;
      height: 32px;
      padding: 0 var(--spacing-sm);
      background: var(--accent-color);
      color: var(--primary-bg);
      border-radius: 50%;
      font-weight: 700;
      font-size: 1rem;
    }

    .points-info {
      display: flex;
      align-items: baseline;
      gap: var(--spacing-xs);
      font-size: 0.9rem;

      .points-label {
        color: var(--text-light);
        font-weight: 500;
      }

      .points-value {
        font-size: 1.1rem;
        font-weight: 700;
        color: var(--accent-color);
        font-family: var(--font-mono);

        &.negative {
          color: var(--error-color);
        }
      }

      .points-total {
        color: var(--text-light);
        font-family: var(--font-mono);
      }

      .points-consumed {
        color: var(--text-light);
        font-size: 0.85rem;
      }
    }
  }

  .panel-body {
    flex: 1;
    align-content: center;
    overflow-y: auto;
    padding: var(--spacing-lg);

    .section {
      margin-bottom: var(--spacing-lg);

      &:last-child {
        margin-bottom: 0;
      }

      .section-title {
        display: flex;
        align-items: center;
        gap: var(--spacing-xs);
        font-size: 1rem;
        font-weight: 600;
        color: var(--title-color);
        margin-bottom: var(--spacing-sm);
        padding-bottom: var(--spacing-xs);
        border-bottom: 1px solid var(--border-color-light);

        .section-label {
          display: inline-flex;
          align-items: center;
          gap: var(--spacing-xs);

          i {
            font-size: 1rem;
            color: var(--accent-color);
          }
        }

        .count {
          font-size: 0.9rem;
          color: var(--text-light);
        }
      }

      .item-list {
        display: flex;
        flex-direction: column;
        gap: var(--spacing-sm);
      }

      .selected-item {
        display: flex;
        gap: var(--spacing-sm);
        justify-content: space-between;
        align-items: center;
        padding: var(--spacing-sm);
        background: var(--input-bg);
        border: 1px solid var(--border-color);
        border-radius: var(--radius-md);
        transition: all var(--transition-fast);

        &:hover {
          border-color: var(--accent-color);
          box-shadow: var(--shadow-sm);
        }

        &.batch-mode {
          cursor: pointer;
        }

        &.selected {
          background: rgba(212, 175, 55, 0.14);
          border-color: var(--accent-color);
          box-shadow: 0 0 0 1px rgba(212, 175, 55, 0.2);

          .batch-check {
            background: var(--accent-color);
            border-color: var(--accent-color);
            color: var(--primary-bg);
          }
        }

        .batch-check {
          flex: none;
          width: 28px;
          height: 28px;
          display: inline-flex;
          align-items: center;
          justify-content: center;
          border: 1px solid var(--border-color);
          border-radius: var(--radius-sm);
          background: var(--card-bg);
          color: var(--text-light);
          font-size: 0.82rem;
        }

        .item-info {
          flex: 1;
          min-width: 0;

          .item-name {
            display: flex;
            align-items: center;
            gap: var(--spacing-xs);
            font-size: 0.9rem;
            font-weight: 600;
            color: var(--text-color);
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;

            .name-text {
              min-width: 0;
              overflow: hidden;
              text-overflow: ellipsis;
            }

            .item-quantity {
              margin-left: var(--spacing-xs);
              font-size: 0.85rem;
              font-weight: 500;
              color: #4caf50;
            }

            .custom-tag {
              flex: none;
              display: inline-flex;
              align-items: center;
              gap: 4px;
              padding: 2px 6px;
              border-radius: var(--radius-sm);
              background: rgba(76, 175, 80, 0.15);
              color: #43a047;
              font-size: 0.75rem;
              font-weight: 600;

              i {
                font-size: 0.7rem;
              }
            }
          }

          .item-cost {
            font-size: 0.85rem;
            color: var(--accent-color);
            font-family: var(--font-mono);
            margin-top: 2px;
          }
        }

        &.is-custom {
          cursor: pointer;
          border-style: dashed;

          &:hover {
            border-color: #43a047;
            box-shadow: 0 0 0 1px rgba(67, 160, 71, 0.2);
          }
        }
      }
    }

    .empty-state {
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      padding: var(--spacing-2xl) var(--spacing-lg);
      text-align: center;

      .empty-icon {
        font-size: 3rem;
        margin-bottom: var(--spacing-md);
        opacity: 0.5;
      }

      .empty-text {
        font-size: 0.95rem;
        color: var(--text-light);
        font-style: italic;
      }
    }
  }

  .panel-footer {
    padding: var(--spacing-lg);
    border-top: 2px solid var(--border-color);
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: var(--spacing-md);

    .total-info {
      display: flex;
      align-items: center;
      gap: var(--spacing-xs);

      .label {
        font-size: 0.95rem;
        color: var(--text-light);
      }

      .value {
        font-size: 1.2rem;
        font-weight: 700;
        color: var(--accent-color);
        font-family: var(--font-mono);
      }
    }

    .clear-btn {
      padding: var(--spacing-sm) var(--spacing-lg);
      background: var(--error-color);
      color: white;
      border: none;
      border-radius: var(--radius-md);
      cursor: pointer;
      font-size: 0.9rem;
      font-weight: 600;
      transition: all var(--transition-fast);

      &:hover {
        background: #b71c1c;
        transform: translateY(-1px);
        box-shadow: var(--shadow-sm);
      }
    }

    .batch-footer {
      width: 100%;
      display: grid;
      grid-template-columns: auto minmax(0, 1fr);
      align-items: center;
      gap: var(--spacing-md);
    }

    .batch-status {
      display: inline-flex;
      align-items: center;
      gap: var(--spacing-xs);
      color: var(--text-light);
      font-size: 0.9rem;

      strong {
        min-width: 28px;
        height: 28px;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        background: var(--accent-color);
        color: var(--primary-bg);
        border-radius: 50%;
        font-family: var(--font-mono);
      }
    }

    .batch-actions {
      min-width: 0;
      display: flex;
      justify-content: flex-end;
      gap: var(--spacing-xs);
      flex-wrap: wrap;
    }

    .batch-action {
      min-height: 34px;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      padding: 6px var(--spacing-sm);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-sm);
      background: var(--input-bg);
      color: var(--title-color);
      font-size: 0.82rem;
      font-weight: 700;
      cursor: pointer;
      transition: all var(--transition-fast);

      i {
        color: var(--accent-color);
      }

      &:hover:not(:disabled) {
        border-color: var(--accent-color);
        box-shadow: var(--shadow-sm);
      }

      &.danger {
        background: rgba(211, 47, 47, 0.08);
        border-color: rgba(211, 47, 47, 0.3);
        color: var(--error-color);

        i {
          color: currentColor;
        }

        &:hover:not(:disabled) {
          background: var(--error-color);
          border-color: var(--error-color);
          color: white;
        }
      }

      &:disabled {
        opacity: 0.48;
        cursor: not-allowed;
      }
    }
  }
}

// 自定义滚动条
.panel-body {
  &::-webkit-scrollbar {
    width: 8px;
  }

  &::-webkit-scrollbar-track {
    background: var(--input-bg);
    border-radius: var(--radius-md);
  }

  &::-webkit-scrollbar-thumb {
    background: var(--border-color);
    border-radius: var(--radius-md);

    &:hover {
      background: var(--border-color-strong);
    }
  }
}

// 响应式设计
@media (max-width: 768px) {
  .selected-panel {
    max-height: none;
    border-width: 1px;
    border-radius: var(--radius-md);

    .panel-header {
      padding: var(--spacing-sm);
      border-bottom: 1px solid var(--border-color);

      .title {
        font-size: 0.95rem;
      }

      .header-actions {
        gap: 4px;
      }

      .batch-toggle {
        min-height: 30px;
        padding: 5px 7px;
        font-size: 0.76rem;
      }

      .count-badge {
        min-width: 28px;
        height: 28px;
        font-size: 0.9rem;
      }

      .points-info {
        flex-wrap: wrap;
        font-size: 0.8rem;

        .points-value {
          font-size: 0.95rem;
        }

        .points-consumed {
          font-size: 0.75rem;
        }
      }
    }

    .panel-body {
      padding: var(--spacing-md);
      max-height: 260px;

      .section {
        .section-title {
          font-size: 0.95rem;
        }

        .selected-item {
          padding: var(--spacing-xs) var(--spacing-sm);
          gap: var(--spacing-xs);

          .batch-check {
            width: 30px;
            height: 30px;
          }

          .item-info {
            .item-name {
              font-size: 0.85rem;
            }

            .item-cost {
              font-size: 0.8rem;
            }
          }
        }
      }

      .empty-state {
        padding: var(--spacing-xl) var(--spacing-md);

        .empty-icon {
          font-size: 2.5rem;
        }

        .empty-text {
          font-size: 0.9rem;
        }
      }
    }

    .panel-footer {
      padding: var(--spacing-sm);
      flex-direction: row;
      align-items: center;
      border-top: none;

      .total-info {
        justify-content: flex-start;
        flex: 1;

        .label {
          font-size: 0.8rem;
        }

        .value {
          font-size: 0.95rem;
        }
      }

      .clear-btn {
        width: auto;
        min-height: 34px;
        padding: 6px var(--spacing-sm);
        font-size: 0.8rem;
      }

      .batch-footer {
        grid-template-columns: 1fr;
        gap: var(--spacing-sm);
      }

      .batch-status {
        justify-content: space-between;
      }

      .batch-actions {
        display: grid;
        grid-template-columns: repeat(2, minmax(0, 1fr));
      }

      .batch-action {
        min-height: 36px;
        padding: 6px 4px;
        font-size: 0.76rem;
      }
    }
  }
}
