
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
  backdrop-filter: blur(2px);
  pointer-events: auto;
  touch-action: pan-y;
}

.modal-container {
  background: var(--card-bg);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-lg);
  border: 1px solid var(--border-color);
  width: 90%;
  max-width: 760px;
  max-height: min(720px, 150vw);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  pointer-events: auto;
  touch-action: auto;
}

.modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--spacing-md) var(--spacing-lg);
  border-bottom: 1px solid var(--border-color);
  background: linear-gradient(135deg, rgba(212, 175, 55, 0.1) 0%, rgba(212, 175, 55, 0.05) 100%);

  .modal-title {
    margin: 0;
    font-size: 1.3rem;
    color: var(--title-color);
    font-weight: 700;
    font-family: var(--font-title);
  }

  .close-button {
    width: 44px;
    height: 44px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex: 0 0 auto;
    background: transparent;
    border: none;
    font-size: 1.35rem;
    cursor: pointer;
    color: var(--text-light);
    border-radius: var(--radius-sm);
    transition: var(--transition-fast);
    touch-action: manipulation;

    &:hover {
      background: var(--border-color-light);
      color: var(--error-color);
    }
  }
}

.modal-content {
  flex: 1;
  overflow-y: auto;
  padding: var(--spacing-lg);
}

.manage-tabs {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: var(--spacing-xs);
  margin-bottom: var(--spacing-lg);
  padding: var(--spacing-xs);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  background: rgba(255, 249, 240, 0.48);
}

.manage-tab {
  min-width: 0;
  min-height: 38px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--title-color);
  font-size: 0.88rem;
  font-weight: 700;
  cursor: pointer;
  transition: var(--transition-fast);

  i,
  span {
    min-width: 0;
  }

  span {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  i {
    color: var(--accent-color);
  }

  &:hover {
    border-color: var(--border-color);
    background: var(--input-bg);
  }

  &.active {
    border-color: var(--accent-color);
    background: var(--accent-color);
    color: var(--primary-bg);

    i {
      color: currentColor;
    }
  }
}

.section-title {
  font-size: 1rem;
  color: var(--title-color);
  margin: 0 0 var(--spacing-md) 0;
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);

  i {
    color: var(--accent-color);
  }
}

.save-section {
  margin-bottom: var(--spacing-xl);
  padding-bottom: var(--spacing-lg);
  border-bottom: 1px dashed var(--border-color);
}

.save-row {
  display: flex;
  gap: var(--spacing-sm);

  .preset-input {
    flex: 1;
    padding: var(--spacing-sm) var(--spacing-md);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    font-size: 0.95rem;
    background: var(--input-bg);
    color: var(--text-color);
    transition: var(--transition-fast);

    &:focus {
      outline: none;
      border-color: var(--accent-color);
      box-shadow: 0 0 0 2px rgba(212, 175, 55, 0.2);
    }

    &::placeholder {
      color: var(--text-light);
    }
  }
}

// 导入区域样式
.import-section {
  margin-bottom: var(--spacing-xl);
  padding-bottom: var(--spacing-lg);
  border-bottom: 1px dashed var(--border-color);
}

.import-row {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);

  .import-hint {
    font-size: 0.85rem;
    color: var(--text-light);
    font-style: italic;
  }
}

// 列表头部（标题 + 全部导出按钮）
.list-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--spacing-md);

  .section-title {
    margin-bottom: 0;
  }
}

.action-button {
  display: flex;
  align-items: center;
  gap: var(--spacing-xs);
  padding: var(--spacing-sm) var(--spacing-md);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition-fast);
  white-space: nowrap;

  i {
    font-size: 0.85rem;
  }

  &.save-button {
    background: linear-gradient(135deg, var(--accent-color) 0%, #b8941f 100%);
    color: white;
    border-color: var(--accent-color);

    &:hover {
      transform: translateY(-1px);
      box-shadow: var(--shadow-sm);
    }

    &.confirm {
      background: linear-gradient(135deg, #ff9800 0%, #f57c00 100%);
      border-color: #ff9800;
      animation: pulse 1s infinite;
    }
  }

  &.load-button {
    background: linear-gradient(135deg, var(--success-color) 0%, #2e7d32 100%);
    color: white;
    border-color: var(--success-color);

    &:hover {
      transform: translateY(-1px);
      box-shadow: var(--shadow-sm);
    }
  }

  &.export-button {
    background: linear-gradient(135deg, #5c6bc0 0%, #3949ab 100%);
    color: white;
    border-color: #5c6bc0;

    &:hover {
      transform: translateY(-1px);
      box-shadow: var(--shadow-sm);
    }
  }

  &.export-all-button {
    background: linear-gradient(135deg, #5c6bc0 0%, #3949ab 100%);
    color: white;
    border-color: #5c6bc0;
    padding: var(--spacing-xs) var(--spacing-md);
    font-size: 0.85rem;

    &:hover {
      transform: translateY(-1px);
      box-shadow: var(--shadow-sm);
    }
  }

  &.import-button {
    background: linear-gradient(135deg, #26a69a 0%, #00897b 100%);
    color: white;
    border-color: #26a69a;

    &:hover {
      transform: translateY(-1px);
      box-shadow: var(--shadow-sm);
    }
  }

  &.delete-button {
    background: var(--card-bg);
    color: var(--error-color);
    border-color: var(--error-color);

    &:hover {
      background: var(--error-color);
      color: white;
    }
  }

  &.confirm-delete {
    background: var(--error-color);
    color: white;
    border-color: var(--error-color);
    animation: pulse 1s infinite;
  }

  &.cancel-button {
    background: var(--card-bg);
    color: var(--text-color);
    border-color: var(--border-color);

    &:hover {
      background: var(--button-bg);
    }
  }

  &.batch-button {
    background: var(--card-bg);
    color: var(--text-color);
    border-color: var(--border-color);
    font-size: 0.85rem;
    padding: var(--spacing-xs) var(--spacing-md);

    &:hover {
      background: var(--button-bg);
      border-color: var(--accent-color);
    }
  }
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.7;
  }
}

.empty-state {
  text-align: center;
  padding: var(--spacing-xl);
  color: var(--text-light);

  .empty-icon {
    font-size: 2.5rem;
    margin-bottom: var(--spacing-md);
    opacity: 0.5;
  }

  p {
    margin: 0 0 var(--spacing-xs) 0;
  }

  .hint {
    font-size: 0.85rem;
    font-style: italic;
  }
}

.preset-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.preset-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--spacing-md);
  background: var(--input-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  transition: var(--transition-fast);

  &:hover {
    border-color: var(--accent-color);
    box-shadow: var(--shadow-sm);
  }

  &.delete-pending {
    border-color: var(--error-color);
    background: rgba(211, 47, 47, 0.05);
  }
}

.preset-main {
  flex: 1;
  min-width: 0;
}

.preset-info {
  display: flex;
  align-items: baseline;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-xs);

  .preset-name {
    font-weight: 600;
    color: var(--title-color);
    font-size: 1rem;
  }

  .preset-time {
    font-size: 0.8rem;
    color: var(--text-light);
    font-family: var(--font-mono);
  }
}

.preset-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-sm);

  .meta-item {
    font-size: 0.85rem;
    color: var(--text-light);

    i {
      margin-right: 2px;
      color: var(--accent-color);
      opacity: 0.7;
    }
  }
}

.preset-actions {
  display: flex;
  gap: var(--spacing-xs);
  margin-left: var(--spacing-md);
}

.modal-footer {
  padding: var(--spacing-md) var(--spacing-lg);
  border-top: 1px solid var(--border-color);
  display: flex;
  justify-content: flex-end;

  .footer-button {
    padding: var(--spacing-sm) var(--spacing-xl);
    background: var(--button-bg);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: var(--transition-fast);
    color: var(--title-color);

    &:hover {
      background: var(--button-hover);
    }
  }
}

// ===================== 冲突弹窗样式 =====================

.conflict-overlay {
  z-index: 10000;
}

.conflict-container {
  max-width: 550px;
}

.conflict-description {
  margin: 0 0 var(--spacing-md) 0;
  font-size: 0.95rem;
  color: var(--text-color);
}

.batch-actions {
  display: flex;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-lg);
  padding-bottom: var(--spacing-md);
  border-bottom: 1px dashed var(--border-color);
}

.conflict-list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);
}

.conflict-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--spacing-md);
  background: var(--input-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
}

.conflict-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
  flex: 1;

  .conflict-name {
    font-weight: 600;
    color: var(--title-color);
    font-size: 0.95rem;
  }

  .conflict-detail {
    font-size: 0.8rem;
    color: var(--text-light);

    i {
      margin-right: 2px;
    }
  }
}

.conflict-options {
  display: flex;
  gap: var(--spacing-sm);
  margin-left: var(--spacing-md);
}

.conflict-option {
  display: flex;
  align-items: center;
  gap: 4px;
  cursor: pointer;
  font-size: 0.85rem;

  input[type='radio'] {
    margin: 0;
    cursor: pointer;
  }

  .option-label {
    font-weight: 500;

    &.overwrite-label {
      color: #ff9800;
    }

    &.rename-label {
      color: #5c6bc0;
    }

    &.skip-label {
      color: var(--text-light);
    }
  }
}

.no-conflict-hint {
  margin: var(--spacing-md) 0 0 0;
  font-size: 0.9rem;
  color: var(--success-color);

  i {
    margin-right: var(--spacing-xs);
  }
}

.conflict-footer {
  gap: var(--spacing-sm);

  .cancel-footer {
    background: var(--card-bg);
    color: var(--text-color);
    border-color: var(--border-color);

    &:hover {
      background: var(--button-bg);
    }
  }

  .confirm-footer {
    background: linear-gradient(135deg, var(--success-color) 0%, #2e7d32 100%);
    color: white;
    border-color: var(--success-color);

    &:hover {
      transform: translateY(-1px);
      box-shadow: var(--shadow-sm);
    }
  }
}

// 响应式设计
@media (max-width: 600px) {
  .modal-container {
    width: 95%;
    max-height: min(640px, 168vw);
  }

  .modal-header {
    padding: var(--spacing-sm) var(--spacing-md);

    .modal-title {
      font-size: 1.16rem;
    }
  }

  .modal-content {
    padding: var(--spacing-md);
  }

  .manage-tabs {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .manage-tab {
    min-height: 36px;
    font-size: 0.82rem;
  }

  .save-row {
    flex-direction: column;
  }

  .import-row {
    flex-direction: column;
    align-items: stretch;

    .import-hint {
      text-align: center;
    }
  }

  .list-header {
    flex-direction: column;
    align-items: stretch;
    gap: var(--spacing-sm);
  }

  .preset-item {
    flex-direction: column;
    align-items: stretch;
    gap: var(--spacing-sm, 8px);
  }

  .preset-actions {
    margin-left: 0;
    justify-content: flex-end;
  }
}
