
.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--spacing-lg);
  margin-bottom: var(--spacing-lg);

  &.full-width {
    grid-template-columns: 1fr;
  }
}

.form-field {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-sm);

  label {
    font-weight: 600;
    color: var(--accent-color);
    font-size: 1rem;
    display: flex;
    align-items: center;
    gap: var(--spacing-xs);
    letter-spacing: 0.5px;

    &.required::after {
      content: '*';
      color: #ff6b6b;
      font-weight: bold;
      margin-left: 2px;
    }
  }
}

.level-input-group {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);

  .number-input-wrapper {
    flex: 1;
  }

  .level-indicator {
    padding: var(--spacing-sm) var(--spacing-md);
    background: var(--card-bg);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    color: var(--accent-color);
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
  }
}

.attributes-panel {
  margin: var(--spacing-2xl) 0 0;

  .panel-header {
    padding: var(--spacing-md) var(--spacing-lg);
    border-bottom: 1px solid var(--border-color);
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: var(--spacing-sm);

    h3 {
      margin: 0;
      color: var(--title-color);
      font-size: 1.2rem;
      font-weight: 700;
    }

    .points-summary {
      display: flex;
      align-items: center;
      gap: var(--spacing-md);
      flex-wrap: wrap;
    }

    .points-badge {
      font-size: 0.9rem;
      color: var(--text-color);
      padding: var(--spacing-xs) var(--spacing-sm);
      background: var(--primary-bg);
      border: 1px solid var(--border-color);
      border-radius: var(--radius-sm);

      strong {
        color: var(--accent-color);
        font-size: 1.1rem;

        &.error {
          color: var(--error-color);
        }

        &.success {
          color: var(--success-color);
        }
      }

      .points-hint {
        font-size: 0.75rem;
        opacity: 0.7;
      }
    }
  }

  .panel-content {
    padding: var(--spacing-lg);
  }

  // 移动端标签（桌面端隐藏）
  .mobile-label {
    display: none;
  }

  .attr-table-header {
    display: grid;
    grid-template-columns: 50px auto 40px auto 50px;
    gap: var(--spacing-md);
    align-items: center;
    padding: var(--spacing-xs) var(--spacing-sm);
    margin-bottom: var(--spacing-sm);
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--text-color-secondary);
    border-bottom: 1px solid var(--border-color);
    text-align: center;

    .col-name {
      text-align: left;
    }

    .col-result {
      text-align: right;
    }
  }

  .attr-row {
    display: grid;
    grid-template-columns: 50px auto 40px auto 50px;
    gap: var(--spacing-md);
    align-items: center;
    padding: var(--spacing-sm);
    border-bottom: 1px solid var(--border-color-light, rgba(255, 255, 255, 0.05));
    transition: background var(--transition-fast);

    &:hover {
      background: var(--primary-bg);
    }

    &:last-of-type {
      border-bottom: none;
    }

    .col-name {
      font-weight: 600;
      color: var(--title-color);
      font-size: 1rem;
    }

    .col-base,
    .col-extra {
      display: flex;
      justify-content: center;
    }

    .col-tier {
      display: flex;
      justify-content: center;
      align-items: center;
    }

    .tier-value {
      font-weight: 600;
      color: var(--text-color-secondary);
      font-size: 1rem;
    }

    .col-result {
      display: flex;
      justify-content: flex-end;
      align-items: center;
    }

    .final-value {
      font-weight: 700;
      font-size: 1.1rem;
      color: var(--accent-color);
    }

    // 去掉 stepper 自带的 label（本行已有属性名列）
    :deep(.form-stepper) {
      .stepper-label {
        display: none;
      }
    }
  }

  // 无额外点时的列布局（4列）
  .attr-table-header:not(:has(+ .attr-row .col-extra)),
  .attr-row:not(:has(.col-extra)) {
    grid-template-columns: 50px auto 40px 50px;
  }

  .status-message {
    padding: var(--spacing-md);
    border-radius: var(--radius-md);
    text-align: center;
    font-weight: 600;
    font-size: 1rem;
    border: 1px solid;
    margin-top: var(--spacing-md);

    .sep {
      margin: 0 var(--spacing-xs);
      opacity: 0.5;
    }

    &.error {
      background: rgba(211, 47, 47, 0.1);
      color: var(--error-color);
      border-color: var(--error-color);
    }

    &.success {
      background: rgba(56, 142, 60, 0.1);
      color: var(--success-color);
      border-color: var(--success-color);
    }

    &.info {
      background: rgba(212, 175, 55, 0.1);
      color: var(--accent-color);
      border-color: var(--accent-color);
    }
  }
}

// 响应式设计
@media (max-width: 768px) {
  .form-row {
    grid-template-columns: 1fr;

    &.full-width {
      grid-template-columns: 1fr;
    }
  }

  .level-input-group {
    flex-direction: column;
    align-items: stretch;
  }

  .location-field {
    .location-options {
      max-height: 300px;
    }

    .location-option {
      .location-label {
        font-size: 0.85rem;
      }
    }
  }

  .attributes-panel {
    .panel-header {
      flex-direction: column;
      align-items: stretch;
    }

    .attr-table-header {
      display: none;
    }

    .mobile-label {
      display: block;
      font-size: 0.75rem;
      font-weight: 600;
      color: var(--text-color-secondary);
      margin-bottom: var(--spacing-xs);
    }

    .attr-row {
      grid-template-columns: 1fr 1fr;
      gap: var(--spacing-sm);
      padding: var(--spacing-md) var(--spacing-sm);

      .col-name {
        grid-column: 1 / -1;
        font-size: 1.1rem;
        padding-bottom: var(--spacing-xs);
        border-bottom: 1px solid var(--border-color-light, rgba(255, 255, 255, 0.05));
      }

      .col-base,
      .col-extra,
      .col-tier,
      .col-result {
        flex-direction: column;
        align-items: flex-start;
      }

      .col-result {
        align-items: flex-end;
      }
    }

    // 无额外点时移动端改为3列（基础点、层级、总属性）
    .attr-row:not(:has(.col-extra)) {
      grid-template-columns: 1fr auto 1fr;

      .col-result {
        align-items: flex-end;
      }
    }
  }
}
