
.selections-container {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-xl);
  max-width: 1600px;
  margin: 0 auto;
}

// 上半部分：选择区域
.selection-area {
  display: flex;
  flex-direction: column;
}

.custom-area {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}

// 下半部分：已选面板
.summary-area {
  height: 600px;
  min-height: 300px;
}

// 响应式设计
@media (max-width: 768px) {
  .selections {
    height: 100%;
    min-height: 0;
  }

  .selections-container {
    position: relative;
    display: grid;
    grid-template-rows: minmax(0, 1fr) auto;
    height: 100%;
    min-height: 0;
    gap: var(--spacing-xs);
    overflow: hidden;
  }

  .selection-area {
    flex: 1 1 0;
    display: flex;
    flex-direction: column;
    min-height: 0;
    min-width: 0;
    max-width: 100%;
    overflow: hidden;

    :deep(.category-tabs) {
      flex: none;
      min-width: 0;
      max-width: 100%;
    }

    :deep(.category-selection-layout) {
      flex: 1 1 0;
      height: auto;
      max-height: none;
      min-height: 0;
      min-width: 0;
      max-width: 100%;
      overflow: hidden;
    }

    :deep(.category-selection-layout .content-area) {
      flex: 1 1 0;
      min-height: 0;
      overflow: hidden;
    }

    :deep(.category-selection-layout .content-main) {
      flex: 1 1 0;
      min-height: 0;
      overflow-x: hidden;
      overflow-y: auto;
      -webkit-overflow-scrolling: touch;
      overscroll-behavior: contain;
      touch-action: pan-y;
    }
  }

  .mobile-utility-dock {
    min-width: 0;
    max-width: 100%;
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: var(--spacing-xs);
    padding-top: var(--spacing-xs);
    border-top: 1px solid var(--border-color);
  }

  .dock-button {
    min-width: 0;
    min-height: 42px;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 4px;
    padding: 6px 4px;
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--input-bg);
    color: var(--title-color);
    font-size: 0.78rem;
    font-weight: 700;
    cursor: pointer;
    user-select: none;
    -webkit-user-select: none;
    touch-action: manipulation;

    i {
      color: var(--accent-color);
    }

    span,
    strong {
      min-width: 0;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }

    strong {
      color: var(--accent-color);
      font-family: var(--font-mono);
      font-size: 0.76rem;
    }

    &.active {
      background: var(--accent-color);
      border-color: var(--accent-color);
      color: var(--primary-bg);

      i,
      strong {
        color: currentColor;
      }
    }
  }

  .mobile-utility-sheet {
    position: absolute;
    left: 0;
    right: 0;
    bottom: 50px;
    z-index: 30;
    max-height: calc(100% - 58px);
    display: flex;
    flex-direction: column;
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--card-bg);
    box-shadow: var(--shadow-lg);
    overflow: hidden;
  }

  .sheet-header {
    flex: none;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--spacing-sm);
    padding: var(--spacing-sm) var(--spacing-md);
    border-bottom: 1px solid var(--border-color);
    background: var(--input-bg);

    h3 {
      margin: 0;
      font-size: 0.95rem;
      font-family: var(--font-body);
      letter-spacing: 0;
    }
  }

  .sheet-close {
    width: 32px;
    height: 32px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border: 1px solid var(--border-color);
    border-radius: var(--radius-sm);
    background: var(--card-bg);
    color: var(--title-color);
    cursor: pointer;
  }

  .sheet-body {
    min-height: 0;
    overflow-y: auto;
    -webkit-overflow-scrolling: touch;
    overscroll-behavior: contain;
    touch-action: pan-y;
    padding: var(--spacing-xs);
  }
}
