
.layout {
  display: flex;
  flex-direction: column;
  width: 100%;
  max-width: 100%;
  min-height: 500px;
  padding: var(--spacing-xl);

  &.is-fullscreen {
    min-height: 100dvh;
  }
}

.main-title {
  text-align: center;
  margin-bottom: var(--spacing-lg);
  color: var(--title-color);
}

@media (max-width: 768px) {
  .layout {
    aspect-ratio: 9 / 17.5;
    min-height: 0;
    padding: var(--spacing-sm);
    gap: var(--spacing-sm);
    overflow: hidden;

    &.is-fullscreen {
      width: 100%;
      min-height: 100dvh;
      aspect-ratio: auto;
    }
  }

  .main-title {
    flex: none;
    margin-bottom: 0;
    font-size: 1.1rem;
    line-height: 1.2;
    letter-spacing: 0;
    white-space: normal;
  }
}

@media (max-width: 480px) {
  .layout {
    aspect-ratio: 9 / 19.5;
  }
}
