
.cascader-wrapper {
  position: relative;
  width: 100%;
}

// 触发器
.cascader-trigger {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--input-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  font-size: 1rem;
  color: var(--text-color);
  transition: all var(--transition-normal);
  box-shadow: var(--shadow-sm);
  cursor: pointer;

  &:hover:not(.is-disabled) {
    border-color: var(--border-color-strong);
  }

  &.is-open {
    border-color: var(--accent-color);
    box-shadow: 0 0 0 3px rgba(212, 175, 55, 0.1);
  }

  &.is-disabled {
    opacity: 0.6;
    cursor: not-allowed;
    background: var(--border-color-light);
  }

  .selected-text {
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;

    &.placeholder {
      color: var(--text-light);
    }
  }

  .trigger-arrow {
    color: var(--accent-color);
    font-size: 0.7rem;
    transition: transform var(--transition-normal);
    margin-left: var(--spacing-sm);

    &.rotated {
      transform: rotate(180deg);
    }
  }
}

// 下拉面板
.cascader-dropdown {
  position: absolute;
  top: calc(100% + 4px);
  left: 0;
  right: 0;
  z-index: 100;
  background: var(--card-bg);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-md);
  overflow: hidden;
}

// 搜索框
.search-box {
  position: relative;
  padding: var(--spacing-sm);
  border-bottom: 1px solid var(--border-color);

  .search-input {
    width: 100%;
    padding: var(--spacing-xs) var(--spacing-sm);
    padding-right: 28px;
    border: 1px solid var(--border-color);
    border-radius: var(--radius-sm);
    font-size: 0.9rem;
    outline: none;
    background: var(--input-bg);
    color: var(--text-color);

    &:focus {
      border-color: var(--accent-color);
    }

    &::placeholder {
      color: var(--text-light);
    }
  }

  .clear-btn {
    position: absolute;
    right: 16px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--text-light);
    cursor: pointer;
    font-size: 0.8rem;
    padding: 2px 4px;

    &:hover {
      color: var(--text-color);
    }
  }
}

// 树形容器
.tree-container {
  max-height: 300px;
  overflow-y: auto;
  padding: var(--spacing-xs) 0;
}

// 搜索结果
.search-results {
  max-height: 300px;
  overflow-y: auto;
}

.search-result-item {
  padding: var(--spacing-sm) var(--spacing-md);
  cursor: pointer;
  transition: background-color var(--transition-fast);
  font-size: 0.9rem;

  &:hover {
    background: var(--hover-bg, rgba(212, 175, 55, 0.1));
  }

  &.is-selected {
    background: rgba(212, 175, 55, 0.15);
    color: var(--accent-color);
    font-weight: 600;
  }

  :deep(.highlight) {
    background: rgba(212, 175, 55, 0.3);
    color: inherit;
    padding: 0 2px;
    border-radius: 2px;
  }
}

.no-results {
  padding: var(--spacing-md);
  text-align: center;
  color: var(--text-light);
  font-size: 0.9rem;
}

// 移动端适配
@media (max-width: 768px) {
  .cascader-trigger {
    min-height: 44px;
  }

  .search-result-item {
    min-height: 44px;
    display: flex;
    align-items: center;
    padding: var(--spacing-sm) var(--spacing-md);
  }

  .search-input {
    min-height: 40px;
  }
}
